-- SCRIPT CÀI ĐẶT BẢNG NGƯỜI DÙNG (AUTHENTICATION)
ALTER SESSION SET "_ORACLE_SCRIPT"=true;

-- 1. Tạo bảng WEB_USER
CREATE TABLE "WEB_USER" (
    "ID" NUMBER(10) GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "USERNAME" VARCHAR2(100) NOT NULL UNIQUE,
    "PASSWORD" VARCHAR2(255) NOT NULL,
    "FULLNAME" NVARCHAR2(200),
    "ROLE" VARCHAR2(50) NOT NULL, -- 'Admin' hoặc 'Staff'
    "CREATED_DATE" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 2. Thêm tài khoản mẫu
-- Mật khẩu mặc định: 123456 (Trong thực tế nên được mã hóa Hash)
INSERT INTO "WEB_USER" ("USERNAME", "PASSWORD", "FULLNAME", "ROLE") 
VALUES ('admin', '123456', 'Quản Trị Viên', 'Admin');

INSERT INTO "WEB_USER" ("USERNAME", "PASSWORD", "FULLNAME", "ROLE") 
VALUES ('staff', '123456', 'Nhân Viên Điều Hành', 'Staff');

-- 3. Cấp quyền cho Role đã tạo trước đó (nếu cần)
GRANT SELECT, INSERT, UPDATE, DELETE ON "WEB_USER" TO TOUR_ADMIN_ROLE;
GRANT SELECT ON "WEB_USER" TO TOUR_STAFF_ROLE;

COMMIT;
PROMPT ==== ĐÃ CÀI ĐẶT THÀNH CÔNG BẢNG NGƯỜI DÙNG ====;
EXIT;
